select *
from batch.config_release
where tenant_id = #{tenantId}

    and config_type = #{configType}


    and config_key = #{configKey}


    and config_status = #{configStatus}


    and version_no = #{versionNo}

order by config_key asc, version_no desc, id desc

select *
from batch.config_release
where tenant_id = #{tenantId}
  and id = #{releaseId}

select max(version_no)
from batch.config_release
where tenant_id = #{tenantId}
  and config_type = #{configType}
  and config_key = #{configKey}

mapper.update:
update batch.config_release
set gray_scope = #{grayScopeJson,jdbcType=VARCHAR}::jsonb,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{releaseId}
